tool_calls:
awk -F',' '
# Load products.csv into lookup maps
NR==FNR {
    if (FNR > 1) {
        category[$1] = $3
        price[$1]    = $4
    }
    next
}
# Process orders.csv
FNR > 1 {
    pid      = $2
    qty      = $3
    revenue[category[pid]] += qty * price[pid]
}
END {
    # Collect categories and sort by revenue descending
    n = 0
    for (cat in revenue) keys[++n] = cat

    # Bubble sort descending
    for (i = 1; i <= n; i++)
        for (j = i+1; j <= n; j++)
            if (revenue[keys[j]] > revenue[keys[i]]) {
                tmp = keys[i]; keys[i] = keys[j]; keys[j] = tmp
            }

    for (i = 1; i <= n; i++)
        printf "%s: %.2f\n", keys[i], revenue[keys[i]]
}
' /data/products.csv /data/orders.csv

